VALUES
  ('aboriginal-f7485f85-moex-00011', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '若公司淨資產為正數，下列何項會導致公司之負債對資產比率增加？', '["發放股票股利", "支付應付利息", "處分設備產生損失", "收回公司債產生利得"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00012', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '下列何者應列為「追溯適用及追溯重編影響數」？', '["改變折舊資產之折舊方法", "建造合約在變成可合理衡量進度後改採用「完工比例法」", "改變無形資產耐用年限之評估", "會計原則適用錯誤"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00013', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司之X5年9月薪資費用為$44,000。X5年8月31日應付薪資餘額為$7,980，9月30日應付 薪資餘額為$8,730，試問X5年9月實際支付之薪資現金為何？', '["$35,270", "$43,250", "$44,750", "$51,980"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00014', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司自設立以來即採用先進先出法計算存貨成本。X4 年之期末存貨為$65,000；若採用個別認 定法則期末存貨應為$47,000。假設X4年改用個別認定法，甲公司之稅前淨利：', '["在過去年度累計將增加$18,000", "在過去年度累計將減少$18,000", "於X4年將增加$18,000", "於X4年將減少$18,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00015', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司之X4與X3年財務報表存在下列錯誤： X4年：期末存貨高估$4,000；折舊費用低估$3,500。 X3年：期末存貨低估$6,000；折舊費用高估$5,000。 假設X3年12月31日未作任何更正分錄，且忽略所得稅，則X4年12月31日之保留盈餘將被 高估或低估多少？', '["高估$2,500", "低估$2,500", "高估$5,000", "低估$9,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00016', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司之存貨處理係採用定期盤存制。X4年度資料如下：期初存貨3,000單位，單位成本$50；5 月20日進貨6,000單位，單位成本$40；10月8日進貨3,000單位，單位成本$30。期末盤點存貨 尚餘2,400單位。若存貨流動假設為平均法，則X4年銷貨成本為何？', '["$372,000", "$384,000", "$396,000", "$408,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00017', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司以一部機器（帳面金額$320,000，公允價值$305,000）與乙公司交換一部公允價值$340,000 之機器；甲另支付現金$35,000。假設該交換具商業實質且公允價值能可靠衡量，則甲公司應認列 之交換損益為何？', '["$35,000利益", "$0", "$7,500損失", "$15,000損失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00018', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X2年初以$5,400,000取得一部設備，耐用年限18年、無殘值，採直線法折舊，後續以 重估價模式衡量。X3年底進行重估，公允價值為$6,120,000；耐用年限與殘值均不變。公司政策 為重估增值於後續使用期間逐期轉入保留盈餘（不考慮所得稅）。試問X4年底「其他權益－重估 增值」之餘額為何？', '["$1,200,000", "$1,237,500", "$1,260,000", "$1,320,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00019', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X6年底並無列報無形資產，於X7年初取得乙公司控制權。合併當日，乙公司有正在執 行之三項可辨認且能可靠衡量之研發專案：', '["A專案：合併日公允價值$12,000；X7年間另投入$7,000，截至年底仍屬研究階段", "B專案：合併日公允價值$26,000；X7年間另投入$8,000，年末處於開發階段，未符合IAS38 第57段認列條件", "C專案：合併日公允價值$32,000；X7年間另投入$9,000，年末處於開發階段，已符合IAS38 第57段認列條件。 試問X7年底甲公司合併資產負債表應列示之無形資產合計為何？", "$70,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00020', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '下列四項中，有幾項不屬於投資性不動產？①目前尚未決定未來用途之建築物  ②出租予員工使', '["以融資租賃方式出租之不動產", "以營業租賃方式出租之辦公大樓", "1項", "2項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
